const body = $items('Webhook PHP (pago nuevo)')[0].json.body || $items('Webhook PHP (pago nuevo)')[0].json;
const adminsCsv = ('59175571497' || '').toString();
const admins = adminsCsv.split(',').map(s => s.trim()).filter(Boolean);
return admins.map(phone => {
  const to = phone.startsWith('+') ? phone : '+' + phone;
  return { json: { to, pago: body } };
});

